args.cypher:
// Find all AAS shells and check which have devices in Hall 3 via hierarchical structures
// First, let's see the actual node structure of the hierarchical structures
MATCH (sm:Submodel {id: 'urn:submodel:hall3:hierarchicalstructures'})
MATCH path = (sm)-[:HAS_ELEMENT*1..4]->(el:SubmodelElement)
WHERE 'Entity' IN labels(el)
RETURN el.idShort, el.smId, el.idShortPath

// Find all FacilityInformation submodels and their parent AAS
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/dfki/SubmodelTemplate/FacilityInformation/1/0'})
RETURN aas.idShort, aas.id, sm.idShort, sm.id

// Explore the HierarchicalStructures submodel of Hall 3
MATCH (sm:Submodel {id: 'urn:submodel:hall3:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, el.smId, labels(el) AS types, el.value AS value

// List all AAS shells
MATCH (aas:AssetAdministrationShell)
RETURN aas.idShort, aas.id ORDER BY aas.idShort

// List all elements in the Hall3 HierarchicalStructures submodel
MATCH (sm:Submodel {id: 'urn:submodel:hall3:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.smId

// Get FacilityInformation properties for Hall3
MATCH (sm:Submodel {id: 'urn:submodel:hall3:facilityinformation'})-[:HAS_ELEMENT]->(el:Property)
RETURN el.idShort, el.value, el.valueType

// Get FacilityInformation properties for Hall4
MATCH (sm:Submodel {id: 'urn:submodel:hall4:facilityinformation'})-[:HAS_ELEMENT]->(el:Property)
RETURN el.idShort, el.value, el.valueType
